<?php require_once('plugins/login-servers.php'); $servers = getenv('ADMINER_SERVERS') ?: ''; $server_list = []; if ($servers) { foreach (explode(',', $servers) as $s) { $parts = explode('=', trim($s)); if (count($parts) == 2) { $server_list[trim($parts[0])] = ['server' => trim($parts[1]), 'driver' => 'server']; } } } if (empty($server_list)) { $server_list['Hata: Env Bulunamadi'] = ['server' => 'db', 'driver' => 'server']; } return new AdminerLoginServers($server_list);
